import React from "react"
import moment from "moment";
import { properties } from '../../properties/properties.js'
var xlsx = require("xlsx");


class Scheduler extends React.Component {

    constructor(props) {
        super(props);
        this.state = {
            results: [], screen: 0, selectedFile: null, amionData: []
        };
    }

    handleselectedFile = event => {
        //console.log(event.target.files[0])
        this.setState({
          selectedFile: event.target.files[0]
        })
      }


    handleUpload = (e) => {

        this.setState({screen: 1})

        e.preventDefault();
        var results = []
        var forAmionStartDate = ""
        var forAmionEndDate = ""

        /*
        var startDate = ""
        var endDate = ""
*/
/*
        var wb = xlsx.readFile(this.state.selectedFile);


        var wsR1 = wb.Sheets[wb.SheetNames[0]];
        var wsR2 = wb.Sheets[wb.SheetNames[1]];
        var wsR3 = wb.Sheets[wb.SheetNames[2]];


        this.findRotation("UC Card", wsR1)
        */
        var reader = new FileReader();
        const scope = this;
        reader.onload = function (e) {

            function findRotation(forWhichRotation, ws, sheetName) {

                var range = xlsx.utils.decode_range(ws['!ref']);

                var yearInfoString = []

                for (let colNum = 0; colNum <= range.e.c; colNum++) {
                    var yearRow = findV(ws[xlsx.utils.encode_cell({r: 0, c: colNum})])
                    if (yearRow.length > 0 && isNaN(yearRow.substring(0,1))) {
                        yearInfoString = yearRow.split(",")
                    }
                }

                var yearInfo = []
                yearInfo = yearInfoString[1].trim().split("-").map(item=>item.trim())
                //console.log(yearInfo)

                var lastDate = ""



                for (let colNum = 0; colNum <= range.e.c; colNum++) {

                    var rotationRow = findV(ws[xlsx.utils.encode_cell({r: 2, c: colNum})])


                    if (rotationRow.length > 0 && !isNaN(rotationRow.substring(0,1))) {

                        var splitDate = rotationRow.split(" ")

                        var yearString = yearInfo[0]

                        var startDate = moment(splitDate[1] + "/" + yearString, "M/D/YYYY").format("YYYY-MM-DD")
                        var endDate = moment(splitDate[3] + "/" + yearString, "M/D/YYYY").format("YYYY-MM-DD")

                        if (lastDate.length > 0 && startDate < lastDate) {
                            startDate = moment(splitDate[1] + "/" + yearInfo[1], "M/D/YYYY").format("YYYY-MM-DD")
                        }
                        if (lastDate.length > 0 && endDate < lastDate) {
                            endDate = moment(splitDate[3] + "/" + yearInfo[1], "M/D/YYYY").format("YYYY-MM-DD")
                        }

                        if (forAmionStartDate === "" || startDate < forAmionStartDate) {
                            forAmionStartDate = startDate
                        }

                        if (forAmionEndDate === "" || endDate > forAmionEndDate) {
                            forAmionEndDate = endDate
                        }


                        lastDate = endDate

                       //console.log("*******************************************************************")
                       //console.log(rotationRow)
                       for (let rowNum = 3; rowNum <= range.e.r; rowNum++) {
                           /*
                            var splitDate = rotationRow.split(" ")
                           if (startDate == "") {
                               startDate = splitDate[1] + "/" + moment().format("YYYY")
                               console.log(startDate)
                           }
                           endDate = splitDate[3] + "/" + moment().format("YYYY")
                           console.log(endDate)
                           */

                           var isRotation = findV(ws[xlsx.utils.encode_cell({r: rowNum, c: colNum})])
                           var data = findV(ws[xlsx.utils.encode_cell({r: rowNum, c: 0})])
                           //if (isRotation === forWhichRotation && data != "OB") {
                            if (isRotation.includes(forWhichRotation)) {
                               var before = ""
                               if (colNum > 1) {
                                   before = findV(ws[xlsx.utils.encode_cell({r: rowNum, c: colNum - 1})])
                               }
                               var after = ""
                               var checkClinics = findV(ws[xlsx.utils.encode_cell({r: 2, c: colNum + 1})])
                               if (checkClinics != "Clinics") {
                                   after = findV(ws[xlsx.utils.encode_cell({r: rowNum, c: colNum + 1})])
                               }
                               var clinic = findV(ws[xlsx.utils.encode_cell({r: rowNum, c: range.e.c})])
                               var lastColumn = findV(ws[xlsx.utils.encode_cell({r: 2, c: range.e.c})])
                               if (lastColumn === "Clinics") {
                                   clinic = ""
                               }
                               //console.log("Name:" + data + " ** before:" + before + " ** rotation:" + forWhichRotation + " ** after:" + after + " ** clinic:" + clinic)

                               results.push({"startDate": startDate, "endDate": endDate, "name": data, "before": before, "after": after, "rotation": isRotation, "clinic": clinic, "sheetName": sheetName, "date": rotationRow })
                           }
                       }
                    }

                }
            }




            function findV(cellValue) {
                var value_v = "";
                if (typeof cellValue !== 'undefined')
                    value_v = cellValue.v
                else
                    value_v = ""
                return value_v;
            }

            function findW(cellValue) {
                var value_w = "";
                if (typeof cellValue !== 'undefined') {
                    value_w = moment(cellValue.w,'M/D/YY').format('MM/DD/YYYY')

                } else {
                    value_w = ""
                }
                return value_w;
            }


            var data = e.target.result;
            let wb = xlsx.read(data, {type: 'binary'});
            //const wsname = readedData.SheetNames[0];
            //const ws = readedData.Sheets[wsname];

            var wsR1 = wb.Sheets[wb.SheetNames[0]];
            var wsR2 = wb.Sheets[wb.SheetNames[1]];
            var wsR3 = wb.Sheets[wb.SheetNames[2]];

            findRotation("UCW", wsR1, wb.SheetNames[0])
            findRotation("UCW", wsR2, wb.SheetNames[1])
            findRotation("UCW", wsR3, wb.SheetNames[2])

            findRotation("UC Card", wsR1, wb.SheetNames[0])
            findRotation("UC Card", wsR2, wb.SheetNames[1])
            findRotation("UC Card", wsR3, wb.SheetNames[2])


            /* Convert array to json*/
            //const dataParse = xlsx.utils.sheet_to_json(ws, {header:1});
            //setFileUploaded(dataParse);

            //console.log(results)
            //return results
            //this.setState({results: results})
            //console.log(forAmionStartDate)
            //console.log(forAmionEndDate)

            var amionData = []

            let headers = new Headers();

            headers.append('Content-Type', 'application/json');
            headers.append('Accept', 'application/json');

            fetch(properties.backend + 'amionmed?startDate=' + forAmionStartDate + '&endDate' + forAmionEndDate, {
                "method": "GET",
                headers: headers
              })
              .then(response => response.json())
              .then(response => {
                //console.log(response);

                amionData = response.data


                scope.setState({results: results, amionData: amionData})

                scope.setState({screen: 2})


            })
            .catch(err => {
              console.log(err);
            });









        };

        reader.readAsBinaryString(this.state.selectedFile)



      }



    componentDidMount() {




      }


          render() {


            var header = ""

            var content = []
            //var items = []

            content.push(<div >
            <input type="hidden" name="todayDate" value={this.state.todayDay} />
            <input type="file" name="" id="" onChange={this.handleselectedFile} />
            <button onClick={this.handleUpload}>Upload</button>
          </div>)


                if (this.state.screen == 1) {
                    content.push(<div><h2>Loading ... </h2></div>)
                }


                if (this.state.screen == 2) {


                    //console.log(this.state.amionData)



                    var R1GroupUCW = Array.from(new Set(this.state.results.filter(filterRec => filterRec.sheetName == "R1" && filterRec.rotation.includes("UCW")).map(groups => groups.date))).map(group => {return {date: group, startDate: this.state.results.filter(Record => Record.date === group && Record.sheetName == "R1" && Record.rotation.includes("UCW"))[0].startDate, endDate: this.state.results.filter(Record => Record.date === group && Record.sheetName == "R1" && Record.rotation.includes("UCW"))[0].endDate, data: this.state.results.filter(Record => Record.date === group && Record.sheetName == "R1" && Record.rotation.includes("UCW"))}});
                    var R2GroupUCW = Array.from(new Set(this.state.results.filter(filterRec => (filterRec.sheetName == "R2" || filterRec.sheetName == "R3") && filterRec.rotation.includes("UCW")).map(groups => groups.date))).map(group => {return {date: group, startDate: this.state.results.filter(Record => Record.date === group && (Record.sheetName == "R2" || Record.sheetName == "R3")&& Record.rotation.includes("UCW"))[0].startDate, endDate: this.state.results.filter(Record => Record.date === group && (Record.sheetName == "R2" || Record.sheetName == "R3")&& Record.rotation.includes("UCW"))[0].endDate, data: this.state.results.filter(Record => Record.date === group && (Record.sheetName == "R2" || Record.sheetName == "R3")&& Record.rotation.includes("UCW"))}});
                    //var R3GroupUCW = Array.from(new Set(this.state.results.filter(filterRec => filterRec.sheetName == "R3" && filterRec.rotation == "UCW").map(groups => groups.date))).map(group => {return {date: group, data: this.state.results.filter(Record => Record.date === group && Record.sheetName == "R3" && Record.rotation == "UCW")}});

                    var R1GroupUCCard = Array.from(new Set(this.state.results.filter(filterRec => filterRec.sheetName == "R1" && filterRec.rotation.includes("UC Card")).map(groups => groups.date))).map(group => {return {date: group, startDate: this.state.results.filter(Record => Record.date === group && Record.sheetName == "R1" && Record.rotation.includes("UC Card"))[0].startDate, endDate: this.state.results.filter(Record => Record.date === group && Record.sheetName == "R1" && Record.rotation.includes("UC Card"))[0].endDate, data: this.state.results.filter(Record => Record.date === group && Record.sheetName == "R1" && Record.rotation.includes("UC Card"))}});
                    var R2GroupUCCard = Array.from(new Set(this.state.results.filter(filterRec => (filterRec.sheetName == "R2" || filterRec.sheetName == "R3") && filterRec.rotation.includes("UC Card")).map(groups => groups.date))).map(group => {return {date: group, startDate: this.state.results.filter(Record => Record.date === group && (Record.sheetName == "R2" || Record.sheetName == "R3")&& Record.rotation.includes("UC Card"))[0].startDate, endDate: this.state.results.filter(Record => Record.date === group && (Record.sheetName == "R2" || Record.sheetName == "R3")&& Record.rotation.includes("UC Card"))[0].endDate, data: this.state.results.filter(Record => Record.date === group && (Record.sheetName == "R2" || Record.sheetName == "R3")&& Record.rotation.includes("UC Card"))}});
                    //var R3GroupUCCard = Array.from(new Set(this.state.results.filter(filterRec => filterRec.sheetName == "R3" && filterRec.rotation == "UC Card").map(groups => groups.date))).map(group => {return {date: group, data: this.state.results.filter(Record => Record.date === group && Record.sheetName == "R3" && Record.rotation == "UC Card")}});


                    //console.log(R1GroupUCW)

                    content.push(<div><h2>UCW</h2><hr></hr></div>)
                    content.push(<div><h3>Residents</h3><hr></hr></div>)

                    R1GroupUCW.map(rec => {
                        content.push(<div><h4>{rec.date}</h4></div>)
                        //content.push(<div><h4>{rec.startDate} - {rec.endDate}</h4></div>)
                        var tr = []
                        rec.data.map(rec2 => {

                            //console.log(rec.startDate + " " + rec.endDate)
                            //console.log(this.state.amionData)
                            //var findAmionData = this.state.amionData.filter(amionRed => moment(amionRed.date, "M-D-YY" ).format("YYYY-MM-DD") >= rec.startDate && moment(amionRed.date, "M-D-YY" ).format("YYYY-MM-DD") <= rec.endDate)
                            var findAmionData = this.state.amionData.filter(amionRed => amionRed.name == "McGregor, Jack")

                            console.log(findAmionData)

                            tr.push(<tr><td style={{borderWidth: "1px", borderStyle: "solid"}}>{rec2.name}</td><td style={{borderWidth: "1px", borderStyle: "solid"}}>{rec2.before}</td><td style={{borderWidth: "1px", borderStyle: "solid"}}>{rec2.rotation}</td><td style={{borderWidth: "1px", borderStyle: "solid"}}>{rec2.after}</td><td style={{borderWidth: "1px", borderStyle: "solid"}}>{rec2.clinic}</td></tr>)
                        })
                        content.push(<div><table style={{borderWidth: "1px", borderStyle: "solid"}}><tr><td>Name</td><td>Before</td><td>Rotation</td><td>After</td><td>Clinic</td></tr>{tr}</table></div>)
                    })

                    content.push(<div><h3>Interns</h3><hr></hr></div>)
                    R2GroupUCW.map(rec => {
                        content.push(<div><h4>{rec.date}</h4></div>)
                        var tr = []
                        rec.data.map(rec2 => {
                            tr.push(<tr><td style={{borderWidth: "1px", borderStyle: "solid"}}>{rec2.name}</td><td style={{borderWidth: "1px", borderStyle: "solid"}}>{rec2.sheetName}</td><td style={{borderWidth: "1px", borderStyle: "solid"}}>{rec2.before}</td><td style={{borderWidth: "1px", borderStyle: "solid"}}>{rec2.rotation}</td><td style={{borderWidth: "1px", borderStyle: "solid"}}>{rec2.after}</td><td style={{borderWidth: "1px", borderStyle: "solid"}}>{rec2.clinic}</td></tr>)
                        })
                        content.push(<div><table style={{borderWidth: "1px", borderStyle: "solid"}}><tr><td>Name</td><td></td><td>Before</td><td>Rotation</td><td>After</td><td>Clinic</td></tr>{tr}</table></div>)
                    })





                    content.push(<div><h2>UC Card</h2><hr></hr></div>)
                    content.push(<div><h3>Residents</h3><hr></hr></div>)

                    R1GroupUCCard.map(rec => {
                        content.push(<div><h4>{rec.date}</h4></div>)
                        var tr = []
                        rec.data.map(rec2 => {

                            //var findAmionData = this.state.amionData.filter(amionRed => moment(amionRed.date, "M-D-YY" ) >= moment(rec.startDate, "")

                            tr.push(<tr><td style={{borderWidth: "1px", borderStyle: "solid"}}>{rec2.name}</td><td style={{borderWidth: "1px", borderStyle: "solid"}}>{rec2.before}</td><td style={{borderWidth: "1px", borderStyle: "solid"}}>{rec2.rotation}</td><td style={{borderWidth: "1px", borderStyle: "solid"}}>{rec2.after}</td><td style={{borderWidth: "1px", borderStyle: "solid"}}>{rec2.clinic}</td></tr>)
                        })
                        content.push(<div><table style={{borderWidth: "1px", borderStyle: "solid"}}><tr><td>Name</td><td>Before</td><td>Rotation</td><td>After</td><td>Clinic</td></tr>{tr}</table></div>)
                    })

                    content.push(<div><h3>Interns</h3><hr></hr></div>)
                    R2GroupUCCard.map(rec => {
                        content.push(<div><h4>{rec.date}</h4></div>)
                        var tr = []
                        rec.data.map(rec2 => {
                            tr.push(<tr><td style={{borderWidth: "1px", borderStyle: "solid"}}>{rec2.name}</td><td style={{borderWidth: "1px", borderStyle: "solid"}}>{rec2.sheetName}</td><td style={{borderWidth: "1px", borderStyle: "solid"}}>{rec2.before}</td><td style={{borderWidth: "1px", borderStyle: "solid"}}>{rec2.rotation}</td><td style={{borderWidth: "1px", borderStyle: "solid"}}>{rec2.after}</td><td style={{borderWidth: "1px", borderStyle: "solid"}}>{rec2.clinic}</td></tr>)
                        })
                        content.push(<div><table style={{borderWidth: "1px", borderStyle: "solid"}}><tr><td>Name</td><td></td><td>Before</td><td>Rotation</td><td>After</td><td>Clinic</td></tr>{tr}</table></div>)
                    })




                }



            return (
<div style={{minHeight: "500px", marginLeft: "50px", marginRight: "50px"}}><h2 className="display-4 text-center">{header}</h2>{content}</div>

            );
          }


  };

  export default Scheduler
